/**
 * Import/Export Modal Component
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import { useState } from 'react';
import { ExportData, ImportResult } from '@/lib/import-export/types';
import { ImportExportManager } from '@/lib/import-export/utils';

interface ImportExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  mode: 'import' | 'export';
  type: 'page' | 'section';
  data?: any;
  onImportSuccess?: (result: ImportResult) => void;
}

export default function ImportExportModal({
  isOpen,
  onClose,
  mode,
  type,
  data,
  onImportSuccess
}: ImportExportModalProps) {
  const [loading, setLoading] = useState(false);
  const [importFile, setImportFile] = useState<File | null>(null);
  const [previewData, setPreviewData] = useState<ExportData | null>(null);
  const [errors, setErrors] = useState<string[]>([]);

  if (!isOpen) return null;

  const handleExport = () => {
    setLoading(true);
    try {
      let exportData: ExportData | null = null;
      
      if (type === 'page') {
        exportData = ImportExportManager.exportPage(data);
      } else if (type === 'section') {
        exportData = ImportExportManager.exportSection(data.id);
      }

      if (exportData) {
        const blob = ImportExportManager.generateDownloadBlob(exportData);
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${type}-${data.slug || data.id}-${Date.now()}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        onClose();
      }
    } catch (error) {
      setErrors(['Export failed: ' + (error as Error).message]);
    } finally {
      setLoading(false);
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setImportFile(file);
    setErrors([]);
    
    try {
      const data = await ImportExportManager.parseUploadedFile(file);
      const validation = ImportExportManager.validateImportData(data);
      
      if (!validation.valid) {
        setErrors(validation.errors);
        return;
      }
      
      setPreviewData(data);
    } catch (error) {
      setErrors(['Failed to parse file: ' + (error as Error).message]);
    }
  };

  const handleImport = async () => {
    if (!previewData) return;
    
    setLoading(true);
    try {
      const response = await fetch('/api/admin/import-export', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'import',
          data: previewData,
          options: {
            overwriteExisting: true,
            autoImportSections: true,
            validateData: true
          }
        })
      });

      const result: ImportResult = await response.json();
      
      if (result.success) {
        onImportSuccess?.(result);
        onClose();
      } else {
        setErrors([result.message, ...result.errors]);
      }
    } catch (error) {
      setErrors(['Import failed: ' + (error as Error).message]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div className="bg-white dark:bg-slate-800 rounded-lg p-6 max-w-2xl w-full mx-4 max-h-[80vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-semibold">
            {mode === 'export' ? 'Export' : 'Import'} {type === 'page' ? 'Page' : 'Section'}
          </h2>
          <button
            onClick={onClose}
            className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200"
          >
            ✕
          </button>
        </div>

        {errors.length > 0 && (
          <div className="mb-4 p-3 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded">
            <h4 className="font-medium text-red-800 dark:text-red-200 mb-2">Errors:</h4>
            <ul className="text-sm text-red-600 dark:text-red-300 space-y-1">
              {errors.map((error, i) => (
                <li key={i}>• {error}</li>
              ))}
            </ul>
          </div>
        )}

        {mode === 'export' ? (
          <div>
            <p className="text-gray-600 dark:text-gray-300 mb-4">
              Export {type === 'page' ? 'page with all its sections' : 'section template'} as JSON file.
            </p>
            <div className="flex justify-end space-x-3">
              <button
                onClick={onClose}
                className="px-4 py-2 text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700 rounded"
              >
                Cancel
              </button>
              <button
                onClick={handleExport}
                disabled={loading}
                className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50"
              >
                {loading ? 'Exporting...' : 'Export'}
              </button>
            </div>
          </div>
        ) : (
          <div>
            <div className="mb-4">
              <label className="block text-sm font-medium mb-2">
                Select JSON file to import:
              </label>
              <input
                type="file"
                accept=".json"
                onChange={handleFileSelect}
                className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
              />
            </div>

            {previewData && (
              <div className="mb-4 p-3 bg-gray-50 dark:bg-slate-700 rounded">
                <h4 className="font-medium mb-2">Preview:</h4>
                <div className="text-sm space-y-1">
                  <p><strong>Type:</strong> {previewData.type}</p>
                  <p><strong>Version:</strong> {previewData.version}</p>
                  <p><strong>Created:</strong> {new Date(previewData.timestamp).toLocaleString()}</p>
                  {previewData.type === 'page' && (
                    <p><strong>Page:</strong> {(previewData.data as any).page?.title}</p>
                  )}
                </div>
              </div>
            )}

            <div className="flex justify-end space-x-3">
              <button
                onClick={onClose}
                className="px-4 py-2 text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700 rounded"
              >
                Cancel
              </button>
              <button
                onClick={handleImport}
                disabled={loading || !previewData}
                className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 disabled:opacity-50"
              >
                {loading ? 'Importing...' : 'Import'}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}